class Solution:
    def minimumScore(self, s, t):
        m = len(t)
        def is_subsequence(a, b):
            it = iter(b)
            return all(c in it for c in a)
        best = m
        for left in range(m + 1):
            for right in range(left, m + 1):
                candidate = t[:left] + t[right:]
                if is_subsequence(candidate, s):
                    best = min(best, right - left)
        return best

