class Solution:
    def minimumScore(self, s, t):
        n, m = len(s), len(t)
        INF = float('inf')
        pre = [INF] * (m + 1)
        pre[0] = 0
        j = 0
        cnt = 0
        for ch in s:
            cnt += 1
            if j < m and ch == t[j]:
                j += 1
                pre[j] = cnt
            if j == m:
                break
        reach_front = j
        if reach_front == m:
            return 0
        suf = [INF] * (m + 1)
        suf[m] = 0
        k = m
        cnt2 = 0
        for ch in reversed(s):
            cnt2 += 1
            if k > 0 and ch == t[k - 1]:
                k -= 1
                suf[k] = cnt2
            if k == 0:
                break
        best = m
        jptr = 0
        for i in range(reach_front + 1):
            if jptr < i:
                jptr = i
            while jptr <= m and pre[i] + suf[jptr] > n:
                jptr += 1
            if jptr <= m:
                best = min(best, jptr - i)
        return best

