var minimumScore = function(s, t) {
    const n = s.length, m = t.length;
    const INF = Infinity;
    const pre = new Array(m + 1).fill(INF);
    pre[0] = 0;
    let j = 0;
    let cnt = 0;
    for (let idx = 0; idx < n; idx++) {
        cnt++;
        if (j < m && s[idx] === t[j]) {
            j++;
            pre[j] = cnt;
        }
        if (j === m) break;
    }
    const reachFront = j;
    if (reachFront === m) return 0;
    const suf = new Array(m + 1).fill(INF);
    suf[m] = 0;
    let k = m;
    let cnt2 = 0;
    for (let idx = n - 1; idx >= 0; idx--) {
        cnt2++;
        if (k > 0 && s[idx] === t[k - 1]) {
            k--;
            suf[k] = cnt2;
        }
        if (k === 0) break;
    }
    let best = m;
    let jptr = 0;
    for (let i = 0; i <= reachFront; i++) {
        if (jptr < i) jptr = i;
        while (jptr <= m && pre[i] + suf[jptr] > n) jptr++;
        if (jptr <= m) best = Math.min(best, jptr - i);
    }
    return best;
};
